import { AnnotationsTrackDisplay } from './AnnotationsTrackDisplay.js';
import { useMarkersByTrack } from '../../../hooks/useMarkersByTrack.js';

export const AnnotationsChartDisplay = () => {
  const tracksWithMarkers = useMarkersByTrack();

  return (
    <>
      {tracksWithMarkers.map(({ markers, hidden, label }, i) => (
        <AnnotationsTrackDisplay
          key={i}
          trackIndex={i}
          drawTopLine={i === 0}
          markers={markers}
          label={label}
          hidden={hidden}
          emphasizeBottomLine={i === tracksWithMarkers.length - 1}
        />
      ))}
    </>
  );
};

AnnotationsChartDisplay['displayName'] = 'AnnotationsChartDisplay';
